class Solution:
    def findKthNumber(self, n, k):
        def count_prefix(prefix, n):
            cur, nxt = prefix, prefix + 1
            total = 0
            while cur <= n:
                total += min(n + 1, nxt) - cur
                cur *= 10
                nxt *= 10
            return total
        cur = 1
        k -= 1  # we've already visited cur=1
        while k > 0:
            cnt = count_prefix(cur, n)
            if cnt <= k:
                k -= cnt
                cur += 1  # skip this entire prefix subtree
            else:
                k -= 1
                cur *= 10  # descend into the prefix
        return cur

