var findKthNumber = function(n, k) {
    function countPrefix(prefix, n) {
        let cur = prefix, nxt = prefix + 1;
        let total = 0;
        while (cur <= n) {
            total += Math.min(n + 1, nxt) - cur;
            cur *= 10;
            nxt *= 10;
        }
        return total;
    }
    let cur = 1;
    k--;
    while (k > 0) {
        const cnt = countPrefix(cur, n);
        if (cnt <= k) {
            k -= cnt;
            cur++;
        } else {
            k--;
            cur *= 10;
        }
    }
    return cur;
};
